var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 낯짝으로 내 앞에 나타나! 당장 썩 안 꺼져?!","JPN":"図々しくよくも会いにこれたものね！　今すぐ消えなさい！！","ENG":"How dare you show your face in front of me! Get out of my sight this instant!","TWN":"你有什麼臉出現在我面前！還不給我滾？！"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"어쨌든 댁이 죽인 거잖아요. 지금 이 사정, 저 사정 다 이해해 달라고 협박하는 거예요?","JPN":"理由はどうあれ、あんたが殺したのには違いないじゃない。今あんたの事情を理解しろって脅すわけ？","ENG":"You're responsible for the death! Now you try to threaten us to \\"understand\\" your situation?!","TWN":"總之人是你殺的！你現在是威脅我要明白你的苦衷嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"가족을 잃은 사람들에겐 당신을 마주보는 것 자체가 힘든 일일 겁니다.","JPN":"家族を失った者にとっては、あなたと向かい合うこと自体が辛いことなんですよ。","ENG":"Imagine how painful it must be for them to look at you, when you're the one who killed one of their beloved.","TWN":"對失去家人的人而言，根本看都不想看你一眼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"차라리…… 그냥 쥐 죽은 듯이 사세요.","JPN":"いっそ……誰ともかかわらずひっそり生きたらいいわ。","ENG":"Just... Never show your face around us ever again.","TWN":"我……還你寧願你什麼都不說，什麼都不做，"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그게 서로를 위해 나은 길 아닌가요?","JPN":"それがお互いのためじゃないですか？","ENG":"Won't that be best for all of us?","TWN":"這樣不是對彼此都好嗎？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MASTER_EP9HALF_MANSION_VOICE","text":{"KOREA":"……그래. 추격할 필요까지는 없으니 이만 돌아오렴.","JPN":"……そう。追撃までは必要ないから、もう戻ってきなさい。","ENG":"...Very well. Stand back. There is no need to chase them.","TWN":"……好，不需要再追，回來吧。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_VOICE","text":{"KOREA":"왜, 놓쳤다던가?","JPN":"何だ、失敗したのか？","ENG":"Why? Did they lose them?","TWN":"怎麼？沒抓到人嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASTER_EP9HALF_MANSION_VOICE","text":{"KOREA":"내 꽃들이 그렇게 허술할 리가. 네 부탁대로 놓아 준 거란다.","JPN":"私の花たちがそんないい加減な仕事するわけないでしょう。あなたが頼んだとおり、行かせてあげたわ。","ENG":"My flowers are not that incompetent. I let them get away as you asked.","TWN":"我的花兒怎麼可能那麼沒用呢？已經照你吩咐的辦妥。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASTER_EP9HALF_MANSION_VOICE","text":{"KOREA":"민병대라니, 나도 참 같잖은 것들과 다 엮여 보네.","JPN":"民兵隊だなんて、くだらないものに首を突っ込んだものね。","ENG":"\\"The Militia\\"... Who thought I would ever cross paths with them.","TWN":"民兵隊？我竟然也會和這種小角色扯上邊。"},"stage":{"bg":"CAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"흠. 일어났구나, 베로니카.","JPN":"ふうん。起きたわね、ベロニカ。","ENG":"Hmm... You're awake, Veronica.","TWN":"哼，你醒啦，貝洛妮卡？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASTER_NPC_MANSION_NULL","text":{"KOREA":"그래, 내 손을 떠나 있는 동안 달콤한 추억은 많이 쌓아 뒀니?","JPN":"どう、私の手から離れている間に甘い思い出はたくさん作れたかしら？","ENG":"So, tell me. Did you make many sweet memories after leaving my wing?","TWN":"怎麼樣？離開我後有累積許多美好的回憶嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"MASTER_NPC_MANSION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"마스터……?! 큭……!","JPN":"マスター……！？　くっ……！","ENG":"Master...?! Kgh...!","TWN":"主人……？！唔……！"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"사제 간의 감동적인 재회를 방해할 생각은 없지만, 지금은 안정을 취하길 바라지.","JPN":"師弟の感動的な再会を邪魔するつもりはないのだが、今は安静にした方がいい。","ENG":"I'd hate to interrupt such a touching reunion of master and pupil, but I need you to rest for now.","TWN":"我無意打擾你們主僕重逢的感人時刻，但現在還是先休養比較好吧。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"마담은 친우로서 나를 도와 준 거야. 해코지할 생각도, 이용할 생각도 없으니 안심하게.","JPN":"マダムは親友として私を手伝ってくれただけなんだ。害をなすつもりも、利用するつもりもないから安心したまえ。","ENG":"Madam is helping me as a friend. Rest assured. I have no intention of hurting you, or using you.","TWN":"夫人是我的好朋友，她只是好心幫忙我。我們沒有要害你，或是利用你的意思，放心吧。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신은…… 누구시죠?","JPN":"あなたは……どなたですか？","ENG":"Who... are you?","TWN":"你……是誰？"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"보통은 시솝이라고들 부르지.","JPN":"通常はシソップと呼ばれている。","ENG":"People call me Sysop.","TWN":"大家都叫我錫索普。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};